module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

parameter IDLE = 1'b0;
parameter DIVIDE = 1'b1;

reg [7:0] dividend_temp;
reg [7:0] divisor_temp;
reg [16:0] SR;
reg [7:0] NEG_DIVISOR;
reg [3:0] cnt;
reg start_cnt;

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        res_valid <= 1'b0;
        start_cnt <= 1'b0;
        cnt <= 4'd0;
        NEG_DIVISOR <= 8'd0;
        dividend_temp <= 8'd0;
        divisor_temp <= 8'd0;
    end else begin
        if (cnt == 4'd8 && !res_valid) begin
            res_valid <= 1'b1;
        end else if (res_valid && res_ready) begin
            res_valid <= 1'b0;
        end

        if (opn_valid && !res_valid) begin
            dividend_temp <= dividend;
            divisor_temp <= divisor;

            SR <= {dividend_temp, 1'b0};

            NEG_DIVISOR <= ~divisor_temp + 1;

            cnt <= 4'd1;
            start_cnt <= 1'b1;
        end else if (start_cnt) begin
            if (cnt[3]) begin
                cnt <= 4'd0;
                start_cnt <= 1'b0;
                SR <= {SR[15:0], 1'b0};
            end else begin
                cnt <= cnt + 1;
                SR <= SR - NEG_DIVISOR;
            end
        end
    end
end

assign result = {SR[15:8], SR[7:0]};
endmodule
